#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define N 200005
#define SN 451
using namespace std;
struct Block{int l,r;}t[SN];int stp[N],nxt[N],Loc[N],a[N],n,block,pre[N]; 
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();return res;
}
inline void getAns(int k){int res=0,lst;while(k<=n)res+=stp[k],lst=k,k=nxt[k];printf("%d %d\n",pre[lst],res);}
inline void Fix(int k,int v)
{
	int i=Loc[k];a[k]=v;drep(k,t[i].l,j)
	{
		if(a[j]+j>t[i].r)stp[j]=1,nxt[j]=j+a[j],pre[j]=j;
		else stp[j]=stp[j+a[j]]+1,nxt[j]=nxt[j+a[j]],pre[j]=pre[j+a[j]];
	}
}
inline void setBlock()
{
	int sn=sqrt(n);block=sn;block+=bool(n%sn);rep(1,n,i)a[i]=read();
	rep(1,block,i){t[i].l=(i-1)*sn+1,t[i].r=i*sn;rep(t[i].l,(i==block)?n:t[i].r,j)Loc[j]=i;}
	t[block].r=n;rep(1,block,i)drep(t[i].r,t[i].l,j) 
	{
		stp[j]=stp[j+a[j]]+1;
		if(j+a[j]>t[i].r)nxt[j]=j+a[j],pre[j]=j;
		else nxt[j]=nxt[j+a[j]],pre[j]=pre[j+a[j]];
	}
	
//	rep(1,block,i)printf("%d %d\n",t[i].l,t[i].r);
}
int main()
{
//	freopen("data.txt","r",stdin);
//	freopen("myans.txt","w",stdout);
	n=read();int m=read();setBlock();rep(1,m,i)
	{int opt=read(),x;opt==1?getAns(read()):(x=read(),Fix(x,read()));}
}
